    def fetch_ohlcv(self, symbol: str, timeframe: str = '1m', since: Int = None, limit: Int = None, params={}) -> List[list]:
        """
        fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market

        https://docs.trade.mudrex.com/docs/historical-kline

        :param str symbol: unified symbol of the market to fetch OHLCV data for
        :param str timeframe: the length of time each candle represents
        :param int [since]: timestamp in ms of the earliest candle to fetch
        :param int [limit]: the maximum amount of candles to fetch
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param int [params.until]: timestamp in ms of the latest candle to fetch
        :param str [params.price]: "mark" to fetch mark price candles
        :returns int[][]: A list of candles ordered, open, high, low, close, volume
        """
        self.load_markets()
        market = self.market(symbol)
        priceType = self.safe_string(params, 'price')
        params = self.omit(params, 'price')
        # the endpoint expects the pair in "BASE/QUOTE" format(comma-separated for multiple)
        assetPair = market['baseId'] + '/' + market['quoteId']
        request = {
            'assets': assetPair,
            'aggregation': self.safe_string(self.timeframes, timeframe, timeframe),
        }
        # the endpoint requires an explicit time window(in seconds)
        duration = self.parse_timeframe(timeframe)
        requestLimit = limit
        if requestLimit is None:
            requestLimit = 500
        now = self.seconds()
        startTime = None
        if since is not None:
            startTime = self.parse_to_int(since / 1000)
        else:
            startTime = now - duration * requestLimit
        endTime = startTime + duration * requestLimit
        until = self.safe_integer(params, 'until')
        if until is not None:
            params = self.omit(params, 'until')
            endTime = self.parse_to_int(until / 1000)
        elif endTime > now:
            endTime = now
        request['start_time'] = startTime
        request['end_time'] = endTime
        response = None
        if priceType == 'mark':
            response = self.marketGetPriceMarkKline(self.extend(request, params))
        else:
            response = self.marketGetPriceKline(self.extend(request, params))
        #
        #     {
        #         "success": True,
        #         "data": {
        #             "asset_ticks": {
        #                 "btc/usdt": [[1782984660, 60681, 60797.6, 60671.8, 60693.3, 275.741]]
        #             }
        #         }
        #     }
        #
        data = self.safe_dict(response, 'data', {})
        assetTicks = self.safe_dict(data, 'asset_ticks', {})
        ohlcvs = self.safe_list(assetTicks, assetPair.lower(), [])
        return self.parse_ohlcvs(ohlcvs, market, timeframe, since, limit)

