    def fetch_balance(self, params={}) -> Balances:
        """
        query for balance and get the amount of funds available for trading or funds locked in orders

        https://docs.trade.mudrex.com/docs

        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.type]: 'swap'(default) or 'spot' - which wallet balance to fetch
        :param str [params.trade_currency]: the settlement currency to query the balance for
        :returns dict: a [balance structure](https://docs.ccxt.com/#/?id=balance-structure)
        """
        self.load_markets()
        type = None
        type, params = self.handle_market_type_and_params('fetchBalance', None, params, 'swap')
        requested = self.safe_string_n(params, ['trade_currency', 'tradeCurrency', 'currency'])
        params = self.omit(params, ['trade_currency', 'tradeCurrency', 'currency'])
        request = {}
        response = None
        if type == 'spot':
            if requested is not None:
                request['currency'] = requested
            response = self.privateGetWalletFunds(self.extend(request, params))
        else:
            if requested is not None:
                request['trade_currency'] = requested
            response = self.privateGetFuturesFunds(self.extend(request, params))
        currency = requested
        if currency is None:
            currency = 'USDT'
        response['currency'] = currency
        return self.parse_balance(response)

    def parse_balance(self, response: Any) -> Balances:
        data = self.safe_dict(response, 'data', {})
        currency = self.safe_string(response, 'currency', 'USDT')
        timestamp = self.milliseconds()
        result = {
            'info': response,
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
        }
        account = self.account()
        futuresBalance = self.safe_string(data, 'balance')
        if futuresBalance is not None:
            # futures wallet: balance is the free/available margin, locked_amount is used, safeBalance derives total
            account['free'] = futuresBalance
            account['used'] = self.safe_string(data, 'locked_amount')
        else:
            # spot wallet: total is the total, withdrawable is free, safeBalance derives used
            account['total'] = self.safe_string(data, 'total')
            account['free'] = self.safe_string(data, 'withdrawable')
        result[currency] = account
        return self.safe_balance(result)

