    def fetch_positions(self, symbols: Strings = None, params={}) -> List[Position]:
        """
        fetch all open positions

        https://docs.trade.mudrex.com/docs

        :param str[] [symbols]: list of unified market symbols
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.trade_currency]: the settlement currency to query positions for
        :returns dict[]: a list of [position structures](https://docs.ccxt.com/#/?id=position-structure)
        """
        self.load_markets()
        q = {}
        response = self.privateGetFuturesPositions(self.extend(q, params))
        data = self.safe_value(response, 'data', [])
        if data is None:
            return []
        rows = self.to_array(data)
        outPos = []
        for i in range(0, len(rows)):
            p = rows[i]
            symRaw = self.safe_string(p, 'symbol')
            m = self.safe_market(symRaw)
            pos = self.parse_position(p, m)
            outPos.append(pos)
        return self.filter_by_array_positions(outPos, 'symbol', symbols, False)

    def fetch_positions_history(self, symbols: Strings = None, since: Int = None, limit: Int = None, params={}) -> List[Position]:
        """
        fetches the history of closed positions

        https://docs.trade.mudrex.com/docs/get-position-history

        :param str[] [symbols]: a list of unified market symbols
        :param int [since]: the earliest time in ms to fetch positions for
        :param int [limit]: the maximum number of position structures to retrieve
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.trade_currency]: the settlement currency to filter positions by
        :returns dict[]: a list of [position structures](https://docs.ccxt.com/#/?id=position-structure)
        """
        self.load_markets()
        symbols = self.market_symbols(symbols)
        request = {}
        if limit is not None:
            request['limit'] = limit
        response = self.privateGetFuturesPositionsHistory(self.extend(request, params))
        #
        #     {
        #         "success": True,
        #         "data": [
        #             {
        #                 "id": "019f1ed6-...",
        #                 "position_type": "SHORT",
        #                 "status": "CLOSED",
        #                 "leverage": "3",
        #                 "entry_price": "1.3112",
        #                 "closed_price": "1.3395",
        #                 "quantity": "34",
        #                 "pnl": "-0.9622",
        #                 "created_at": "2026-07-01T10:18:57Z",
        #                 "updated_at": "2026-07-01T18:00:21Z",
        #                 "symbol": "CAKEUSDT",
        #                 "trade_currency": "USDT"
        #             }
        #         ]
        #     }
        #
        data = self.safe_list(response, 'data', [])
        positions = self.parse_positions(data, symbols)
        return self.filter_by_since_limit(positions, since, limit)

    def parse_position(self, position: dict, market: Market = None) -> Position:
        market = self.safe_market(None, market)
        ms = self.safe_string(position, 'symbol')
        symbol = self.safe_symbol(ms, market)
        # open positions use "order_type", closed positions(history) use "position_type"
        rawSide = self.safe_string_upper_2(position, 'order_type', 'position_type')
        side = None
        if rawSide == 'LONG':
            side = 'long'
        elif rawSide == 'SHORT':
            side = 'short'
        ts = self.parse8601(self.safe_string(position, 'updated_at'))
        if ts is None:
            ts = self.parse8601(self.safe_string(position, 'created_at'))
        quantityString = self.safe_string(position, 'quantity')
        entryPriceString = self.safe_string(position, 'entry_price')
        contractSizeString = self.safe_string(market, 'contractSize', '1')
        notional = None
        if (quantityString is not None) and (entryPriceString is not None):
            notional = self.parse_number(Precise.string_mul(Precise.string_mul(quantityString, entryPriceString), contractSizeString))
        initialMargin = self.safe_string(position, 'initial_margin')
        return {
            'info': position,
            'id': self.safe_string(position, 'id'),
            'symbol': symbol,
            'timestamp': ts,
            'datetime': self.iso8601(ts),
            'isolated': True,
            'hedged': False,
            'side': side,
            'contracts': self.safe_number(position, 'quantity'),
            'contractSize': self.safe_number(market, 'contractSize'),
            'entryPrice': self.safe_number(position, 'entry_price'),
            'markPrice': None,
            'lastPrice': self.safe_number(position, 'closed_price'),  # exit price for closed positions
            'notional': notional,
            'leverage': self.safe_integer(position, 'leverage'),
            'collateral': self.parse_number(initialMargin),
            'initialMargin': self.parse_number(initialMargin),
            'initialMarginPercentage': None,
            'maintenanceMargin': self.safe_number(position, 'maintenance_margin'),
            'maintenanceMarginPercentage': None,
            'unrealizedPnl': None,
            'realizedPnl': self.safe_number(position, 'pnl'),  # realized pnl for closed positions
            'liquidationPrice': self.safe_number(position, 'liquidation_price'),
            'marginMode': 'isolated',
            'percentage': None,
        }

    def close_position(self, symbol: str, side: OrderSide = None, params={}) -> Order:
        """
        closes an open position for a market

        https://docs.trade.mudrex.com/docs

        :param str symbol: unified CCXT market symbol
        :param str [side]: 'buy' or 'sell', not required by mudrex
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.position_id]: the id of the position to close, resolved from the symbol if not provided
        :param float [params.amount]: the amount to close for a partial close, closes the whole position if not provided
        :returns dict: an [order structure](https://docs.ccxt.com/#/?id=order-structure)
        """
        self.load_markets()
        positionId = self.safe_string(params, 'position_id')
        amount = self.safe_value(params, 'amount')
        if positionId is None:
            market = self.market(symbol)
            positions = self.fetch_positions([symbol], params)
            for i in range(0, len(positions)):
                p = positions[i]
                if side is not None and p['side'] != side:
                    continue
                if p['symbol'] == market['symbol']:
                    positionId = self.safe_string(p, 'id')
                    break
        if positionId is None:
            raise OrderNotFound(self.id + ' closePosition() could not resolve position_id')
        request = {
            'position_id': positionId,
        }
        if amount is not None:
            orderType = self.safe_string_upper(params, 'order_type', 'LIMIT')
            request['order_type'] = orderType
            request['quantity'] = self.amount_to_precision(symbol, amount)
            lp = self.safe_string(params, 'limit_price')
            if orderType == 'LIMIT' and lp is not None:
                request['limit_price'] = lp
            params = self.omit(params, ['order_type', 'limit_price', 'amount', 'position_id'])
            return self.privatePostFuturesPositionsPositionIdClosePartial(self.extend(request, params))
        params = self.omit(params, ['position_id'])
        return self.privatePostFuturesPositionsPositionIdClose(self.extend(request, params))

    def add_margin(self, symbol: str, amount: float, params={}) -> MarginModification:
        """
        add margin to a position

        https://docs.trade.mudrex.com/docs

        :param str symbol: unified market symbol
        :param float amount: amount of margin to add
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.position_id]: the id of the position to add margin to, resolved from the symbol if not provided
        :returns dict: a [margin structure](https://docs.ccxt.com/#/?id=add-margin-structure)
        """
        self.load_markets()
        positionId = self.safe_string(params, 'position_id')
        if positionId is None:
            positions = self.fetch_positions([symbol], params)
            for i in range(0, len(positions)):
                p = positions[i]
                if p['symbol'] == symbol:
                    positionId = self.safe_string(p, 'id')
                    break
        if positionId is None:
            raise OrderNotFound(self.id + ' addMargin() could not resolve position_id')
        request = {
            'position_id': positionId,
            'margin': self.cost_to_precision(symbol, amount),
        }
        params = self.omit(params, ['position_id'])
        return self.privatePostFuturesPositionsPositionIdAddMargin(self.extend(request, params))

    def reduce_margin(self, symbol: str, amount: float, params={}) -> MarginModification:
        """
        remove margin from a position

        https://docs.trade.mudrex.com/docs

        :param str symbol: unified market symbol
        :param float amount: the amount of margin to remove
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :returns dict: a [margin structure](https://docs.ccxt.com/#/?id=reduce-margin-structure)
        """
        return self.add_margin(symbol, -amount, params)

    def fetch_my_trades(self, symbol: Str = None, since: Int = None, limit: Int = None, params={}) -> List[Trade]:
        """
        fetch all trades made by the user

        https://docs.trade.mudrex.com/docs

        :param str [symbol]: unified market symbol
        :param int [since]: the earliest time in ms to fetch trades for
        :param int [limit]: the maximum number of trade structures to retrieve
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.trade_currency]: the settlement currency to filter trades by
        :returns Trade[]: a list of [trade structures](https://docs.ccxt.com/#/?id=trade-structure)
        """
        self.load_markets()
        market = None
        if symbol is not None:
            market = self.market(symbol)
        request = {}
        if limit is not None:
            request['limit'] = limit
        response = self.privateGetFuturesFeeHistory(self.extend(request, params))
        data = self.safe_value(response, 'data', [])
        rows = self.to_array(data)
