    def parse_trade(self, trade: dict, market: Market = None) -> Trade:
        ms = self.safe_string(trade, 'symbol')
        market = self.safe_market(ms, market)
        symbol = market['symbol']
        ts = self.parse8601(self.safe_string(trade, 'created_at'))
        if ts is None:
            ts = self.safe_integer(trade, 'time')
        side = self.safe_string_lower_2(trade, 'side', 'order_type')
        tradeSide = None
        if side == 'buy' or side == 'long':
            tradeSide = 'buy'
        elif side == 'sell' or side == 'short':
            tradeSide = 'sell'
        feeType = self.safe_string_upper(trade, 'fee_type')
        takerOrMaker = None
        if feeType == 'TRANSACTION':
            takerOrMaker = 'taker'
        elif feeType == 'REBATE':
            takerOrMaker = 'maker'
        fee = None
        feeCost = self.safe_number(trade, 'fee_amount')
        if feeCost is not None:
            fee = {
                'cost': feeCost,
                'currency': self.safe_string(trade, 'trade_currency'),
            }
        return self.safe_trade({
            'info': trade,
            'timestamp': ts,
            'datetime': self.iso8601(ts),
            'symbol': symbol,
            'id': self.safe_string_2(trade, 'execId', 'id'),
            'order': self.safe_string(trade, 'order_id'),
            'type': self.safe_string_lower(trade, 'trigger_type'),
            'side': tradeSide,
            'takerOrMaker': takerOrMaker,
            'price': self.safe_number(trade, 'price'),
            'amount': self.safe_number_2(trade, 'size', 'quantity'),
            'cost': self.safe_number(trade, 'transaction_amount'),
            'fee': fee,
        }, market)

    def transfer(self, code: str, amount: float, fromAccount: str, toAccount: str, params={}) -> TransferEntry:
        """
        transfer currency internally between wallets on the same account

        https://docs.trade.mudrex.com/docs

        :param str code: unified currency code
        :param float amount: amount to transfer
        :param str fromAccount: 'spot' or 'futures'
        :param str toAccount: 'spot' or 'futures'
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :returns dict: a [transfer structure](https://docs.ccxt.com/#/?id=transfer-structure)
        """
        mp = {
            'spot': 'SPOT',
            'SPOT': 'SPOT',
            'futures': 'FUTURES',
            'future': 'FUTURES',
            'FUTURES': 'FUTURES',
        }
        fw = self.safe_string(mp, fromAccount, fromAccount.upper())
        tw = self.safe_string(mp, toAccount, toAccount.upper())
        body = {
            'from_wallet_type': fw,
            'to_wallet_type': tw,
            'amount': self.number_to_string(amount),
        }
        useInr = False
        if code == 'INR':
            useInr = True
        else:
            # default USDT does not use the inr path
            tradeCurrency = self.safe_string_2(params, 'trade_currency', 'tradeCurrency')
            if tradeCurrency == 'INR':
                useInr = True
        response = None
        if useInr:
            response = self.privatePostFuturesTransfersInr(self.extend(body, params))
        else:
            response = self.privatePostWalletFuturesTransfer(self.extend(body, params))
        data = self.safe_dict(response, 'data', response)
        return {
            'info': response,
            'id': self.safe_string(data, 'id'),
            'timestamp': None,
            'datetime': None,
            'currency': code,
            'amount': amount,
            'fromAccount': fw,
            'toAccount': tw,
            'status': 'ok',
        }
